var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 이렇게 셋이 다 모이니까 정말 옛날로 돌아간 기분이네.","JPN":"ハハ、こうやって3人で集まると本当に昔に戻ったような気分です。","ENG":"Haha, it sure feels like the good old days, having us three working together.","TWN":"呵呵，我們三個現在這樣聚在一起，感覺好像回到過去一樣。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"수연이 너도 통신이 아니라 직접 왔으면 더 좋았을 텐데.","JPN":"キズナも通信じゃなくて直接来れたらよかったのに。","ENG":"It would have been nice if you could've joined us in person, Sooyeon.","TWN":"真希望秀妍你不是透過通訊，而是親自來到我們當中。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"흥, 능청떨기는.","JPN":"ふん、とぼけたことを。","ENG":"Hmph, save it.","TWN":"哼，少在那邊假惺惺！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"리플레이서 사태가 일어났을 때도 나와 스승님은 그곳에 있었어.","JPN":"リプレイサー事件が起こった時も、私と師匠はそこにいた。","ENG":"I was there with Master when the Replacer incident took place.","TWN":"克隆集團事件發生時，我和師父都在場。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"너도 분명 어딘가에 숨어서 전부 관측하고 있었을 텐데?","JPN":"あなたもきっとどこかに隠れて全部みていたんでしょう？","ENG":"I'm sure you were hiding somewhere nearby, keeping tabs on everything.","TWN":"你應該也躲在某處觀察著情況吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이것 참, 수연이한테는 아무것도 감출 수가 없네.","JPN":"やれやれ、キズナには隠し事ができないね。","ENG":"Oh my. I really can't hide anything from you, can I?","TWN":"真是的，什麼都逃不過你的法眼呢！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"맞아. 너와 스승님이 자기 역할을 잘 해 준 덕분에 귀여운 후배를 더 괴롭힐 필요가 없었지.","JPN":"そうだな。君と師匠が自分の役割を十分果たしてくれたおかげで、可愛い後輩くんを苦しめる必要はなかった。","ENG":"You're right. I didn't have to harass my cute little replacement anymore, since you and the Master played your roles so faithfully.","TWN":"沒錯，拜你和師父所賜，我省下不少力氣呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"나유빈, 너 대체 뭘 꾸미고 다니는 거냐?","JPN":"イチノセ、いったい何を企んでいるんだ？","ENG":"What are you plotting, Yubin?","TWN":"羅瑜斌，你到底在打什麼主意？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"무슨 생각인지는 모르겠지만 지금이라도 그만두는 게 좋아.","JPN":"どういうつもりかわからないが、今からでもやめた方がいい。","ENG":"Whatever it is, it'd be wise to drop it sooner than later.","TWN":"雖然我不知道你想幹嘛，但我勸你還是打消那個念頭比較好。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"클리포트 인자라는 건 네 생각보다 훨씬 더 위험한 힘이다.","JPN":"クリフォト・ファクターはお前が思うより遥かに危険な力だ。","ENG":"Qliphoth Factor is far more dangerous than you'd think.","TWN":"卡巴拉因子的力量比你想像中還危險。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"함부로 가지고 놀 만한 게 아니야.","JPN":"むやみに弄んでいいものではない。","ENG":"It's not something to be toyed with lightly.","TWN":"不是你可以隨意拿去把玩的！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"만약 나에 대한 원한 때문에 이런 일을 하는 거라면…….","JPN":"もし、私への恨みでこんなことをしているのなら……","ENG":"If this is about your grudge against me…","TWN":"如果你這麼做是想報復我……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지난번에도 말씀드렸을 텐데요. 원한 같은 건 없다고요.","JPN":"この前も申し上げたと思いますが。恨みなんかありませんよ。","ENG":"Haven't I already told you? I don't hold any grudges against you.","TWN":"我之前應該有說過吧？我沒有要報復師父的意思。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"전, 여전히 세상을 위해 싸우고 있습니다.","JPN":"僕は相変わらず世界のために戦っています。","ENG":"I'm still fighting for the world.","TWN":"我，仍然是為世界而戰。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"관리국과 방식은 조금 다르지만요.","JPN":"管理局とやり方は少し違いますが。","ENG":"Although my methods are slightly different from the Administration's.","TWN":"只是方式和管理局不同而已。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그럼 계속 가시죠. 목적지가 얼마 남지 않았으니까요.","JPN":"では進みましょう。目的地まであと少しですから。","ENG":"Let's keep going, shall we? We're almost there.","TWN":"我們繼續往前吧，就快到目的地了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};